    UniffiLib.INSTANCE.uniffi_uniffi_ledger_fn_method_llamaengine_generate(
        it, FfiConverterString.lower(`prompt`),FfiConverterUInt.lower(`nPredict`),FfiConverterFloat.lower(`temperature`),_status)
}
    }
