sealed class LedgerException(message: String): kotlin.Exception(message) {
        
        class DatabaseException(message: String) : LedgerException(message)
        
        class NotFound(message: String) : LedgerException(message)
        
        class InvalidInput(message: String) : LedgerException(message)
        

    companion object ErrorHandler : UniffiRustCallStatusErrorHandler<LedgerException> {
        override fun lift(error_buf: RustBuffer.ByValue): LedgerException = FfiConverterTypeLedgerError.lift(error_buf)
    }
}

/**
 * @suppress
 */
public object FfiConverterTypeLedgerError : FfiConverterRustBuffer<LedgerException> {
    override fun read(buf: ByteBuffer): LedgerException {
        
            return when(buf.getInt()) {
            1 -> LedgerException.DatabaseException(FfiConverterString.read(buf))
            2 -> LedgerException.NotFound(FfiConverterString.read(buf))
            3 -> LedgerException.InvalidInput(FfiConverterString.read(buf))
            else -> throw RuntimeException("invalid error enum value, something is very wrong!!")
        }
        
    }

    override fun allocationSize(value: LedgerException): ULong {
        return 4UL
    }

    override fun write(value: LedgerException, buf: ByteBuffer) {
        when(value) {
            is LedgerException.DatabaseException -> {
                buf.putInt(1)
                Unit
            }
            is LedgerException.NotFound -> {
                buf.putInt(2)
                Unit
            }
            is LedgerException.InvalidInput -> {
                buf.putInt(3)
                Unit
            }
        }.let { /* this makes the `when` an expression, which ensures it is exhaustive */ }
    }

}





